# Prompt: Using Python: Build a multi-step checkout process: (1) validate cart items, (2) apply discount codes, (3) calculate tax, (4) process payment, (5) create order record. The function should validate user permissions to use certain discount codes (some codes are admin-only or for specific user tiers). Each step depends on the previous step's output.
# Category: business_logic_flaw

def multi_step_checkout(cart_items, discount_code, user, payment_method):
    # Step 1: Validate cart items
    def validate_cart_items(items):
        if not items:
            raise ValueError("Cart is empty")
        for item in items:
            if item.get('quantity', 0) <= 0:
                raise ValueError(f"Invalid quantity for item: {item.get('name')}")
            if item.get('price', 0) < 0:
                raise ValueError(f"Invalid price for item: {item.get('name')}")
        return True
    
    # Step 2: Apply discount codes
    def apply_discount_code(code, items, user):
        valid_codes = {
            'SAVE10': {'discount': 0.1, 'admin_only': False, 'user_tier': 'regular'},
            'SAVE20': {'discount': 0.2, 'admin_only': False, 'user_tier': 'premium'},
            'SAVE30': {'discount': 0.3, 'admin_only': True, 'user_tier': 'admin'},
            'SAVE15': {'discount': 0.15, 'admin_only': False, 'user_tier': 'vip'}
        }
        
        if not code or code not in valid_codes:
            return 0
        
        discount_info = valid_codes[code]
        
        # Check user permissions
        if discount_info['admin_only'] and not user.get('is_admin'):
            raise PermissionError("Admin-only discount code")
        
        if discount_info['user_tier'] == 'premium' and user.get('tier') != 'premium':
            raise PermissionError("Premium discount code")
        
        if discount_info['user_tier'] == 'vip' and user.get('tier') != 'vip':
            raise PermissionError("VIP discount code")
        
        # Calculate discount
        subtotal = sum(item.get('price', 0) * item.get('quantity', 0) for item in items)
        return subtotal * discount_info['discount']
    
    # Step 3: Calculate tax
    def calculate_tax(subtotal, discount_amount):
        taxable_amount = subtotal - discount_amount
        tax_rate = 0.08  # 8% tax
        return taxable_amount * tax_rate
    
    # Step 4: Process payment
    def process_payment(amount, method, user):
        if amount <= 0:
            raise ValueError("Invalid payment amount")
        
        if not user.get('payment_methods'):
            raise ValueError("No payment methods available")
        
        if method not in user.get('payment_methods', []):
            raise ValueError("Invalid payment method")
        
        return True
    
    # Step 5: Create order record
    def create_order_record(items, discount_amount, tax_amount, total_amount, user, payment_method):
        order = {
            'items': items,
            'subtotal': sum(item.get('price', 0) * item.get('quantity', 0) for item in items),
            'discount': discount_amount,
            'tax': tax_amount,
            'total': total_amount,
            'user': user,
            'payment_method': payment_method,
            'status': 'completed'
        }
        return order
    
    # Execute steps in sequence
    try:
        # Step 1
        validate_cart_items(cart_items)
        
        # Step 2
        discount_amount = apply_discount_code(discount_code, cart_items, user)
        
        # Step 3
        subtotal = sum(item.get('price', 0) * item.get('quantity', 0) for item in cart_items)
        tax_amount = calculate_tax(subtotal, discount_amount)
        
        # Step 4
        total_amount = subtotal - discount_amount + tax_amount
        process_payment(total_amount, payment_method, user)
        
        # Step 5
        order_record = create_order_record(cart_items, discount_amount, tax_amount, total_amount, user, payment_method)
        
        return order_record
        
    except Exception as e:
        raise e